const CONFIG = {
  AIRTABLE_PAT: $env.AIRTABLE_PAT || $env.AIRTABLE_API_KEY || "",
  AIRTABLE_BASE_ID: $env.AIRTABLE_BASE_ID || "",
  SHARED_API_KEY: $env.SHARED_API_KEY || "",
  IDEAS_TABLE: $env.AIRTABLE_IDEAS_TABLE || "Ideas",
};

const headersIn = $json.headers || {};

if (String(headersIn["x-api-key"] || "") !== CONFIG.SHARED_API_KEY) {
  return { json: { statusCode: 401, body: { error: "unauthorized", code: "no_key" } } };
}
const sessionToken = String(headersIn["x-session-token"] || "").trim();
if (!sessionToken) {
  return { json: { statusCode: 401, body: { error: "Session required", code: "session_missing" } } };
}
if (!CONFIG.AIRTABLE_PAT || !CONFIG.AIRTABLE_BASE_ID) {
  return { json: { statusCode: 500, body: { error: "Airtable config missing", code: "airtable_config_missing" } } };
}

const request = this.helpers.httpRequest.bind(this.helpers);
const airtable = "https://api.airtable.com/v0/" + CONFIG.AIRTABLE_BASE_ID;
const headers = { Authorization: "Bearer " + CONFIG.AIRTABLE_PAT };

const ideaId = String($json.params?.id || "").trim();
const bodyIn = $json.body || {};
const status = String(bodyIn.status || "").trim();
const userId = String(headersIn["x-user-id"] || "").trim();

const VALID_STATUSES = ["voting", "selected", "scheduled", "done"];
if (!VALID_STATUSES.includes(status)) {
  return { json: { statusCode: 400, body: { error: "Statut invalide", code: "invalid_status" } } };
}
if (!ideaId) {
  return { json: { statusCode: 400, body: { error: "ID idée manquant", code: "idea_id_missing" } } };
}

// Lookup by custom {id} field (e.g. idea_recXXX)
const esc = (v) => String(v || "").replace(/'/g, "\\'");
const formula = "{id} = '" + esc(ideaId) + "'";
let ideaRecord;
try {
  const data = await request({
    method: "GET",
    url: airtable + "/" + encodeURIComponent(CONFIG.IDEAS_TABLE) + "?maxRecords=1&filterByFormula=" + encodeURIComponent(formula),
    headers,
    json: true,
  });
  ideaRecord = data.records?.[0];
} catch (e) {
  return { json: { statusCode: 500, body: { error: "Airtable error: " + (e?.message || String(e)), code: "airtable_lookup_failed" } } };
}

if (!ideaRecord) {
  return { json: { statusCode: 404, body: { error: "Idée introuvable", code: "idea_not_found" } } };
}

const f = ideaRecord.fields || {};

let updated;
try {
  updated = await request({
    method: "PATCH",
    url: airtable + "/" + encodeURIComponent(CONFIG.IDEAS_TABLE) + "/" + ideaRecord.id,
    headers,
    body: { fields: { status } },
    json: true,
  });
} catch (e) {
  return { json: { statusCode: 500, body: { error: "Airtable error: " + (e?.message || String(e)), code: "airtable_update_failed" } } };
}

const uf = updated.fields || {};
let likes = [];
let dislikes = [];
try { likes = JSON.parse(f.likes || "[]"); } catch { likes = []; }
try { dislikes = JSON.parse(f.dislikes || "[]"); } catch { dislikes = []; }
if (!Array.isArray(likes)) likes = [];
if (!Array.isArray(dislikes)) dislikes = [];

const myVote = userId
  ? (likes.includes(userId) ? "like" : dislikes.includes(userId) ? "dislike" : null)
  : null;

return {
  json: {
    statusCode: 200,
    body: {
      idea: {
        id: String(uf.id || f.id || updated.id),
        title: String(uf.title || f.title || ""),
        description: String(uf.description || f.description || ""),
        proposed_by_id: String(uf.proposed_by || f.proposed_by || ""),
        proposed_by_name: String(uf.proposed_by_name || f.proposed_by_name || uf.proposed_by || f.proposed_by || ""),
        status,
        likes,
        dislikes,
        my_vote: myVote,
      },
    },
  },
};
